"""RULER loader — synthetic long-context retrieval/aggregation tasks.

Manual download / generation (no auto-downloads):
    Official source: https://github.com/NVIDIA/RULER
    RULER data is GENERATED by the official scripts (per context length and
    task). Run the official generation for the desired task/length and place
    the resulting JSONL as ``ruler.jsonl`` in the local dataset directory.
"""

from __future__ import annotations

from pathlib import Path

from benchmarks.external.loaders import _common
from benchmarks.external.schema import DatasetCheck, Task, Turn, read_jsonl

NAME = "ruler"
OFFICIAL_URL = "https://github.com/NVIDIA/RULER"
PINNED_VERSION = "RULER generator (pin repo commit + generation config at generation time)"
PINNED_SHA256: str | None = None  # record via check() after generation
DATA_FILENAME = "ruler.jsonl"
DOWNLOAD_INSTRUCTIONS = (
    "Generate the task data with the official RULER scripts and save the "
    f"JSONL output as {DATA_FILENAME} in the dataset directory."
)


def load(data_dir: str | Path) -> list[Task]:
    path = _common.require_data_file(NAME, data_dir, DATA_FILENAME, OFFICIAL_URL, DOWNLOAD_INSTRUCTIONS)
    tasks: list[Task] = []
    for item in read_jsonl(path):
        haystack = str(item.get("input", ""))
        question = str(item.get("query", ""))
        if not question and haystack:
            question = haystack.splitlines()[-1]
        tasks.append(Task(
            task_id=str(item.get("index", len(tasks))),
            benchmark=NAME,
            question=question,
            answers=tuple(str(answer) for answer in item.get("outputs", [])),
            sessions=((Turn(role="context", content=haystack),),),
            metric="exact_match",
            metadata={"length": item.get("length")},
        ))
    return tasks


def check(data_dir: str | Path) -> DatasetCheck:
    return _common.run_check(
        name=NAME, data_dir=data_dir, data_filename=DATA_FILENAME,
        official_url=OFFICIAL_URL, instructions=DOWNLOAD_INSTRUCTIONS,
        pinned_sha256=PINNED_SHA256, load=load,
    )


if __name__ == "__main__":
    import sys as _sys
    _sys.exit(_common.check_cli(_sys.modules[__name__]))
